  // A = (DATA_TYPE (*)[NK])__builtin_assume_aligned(A, 64);
  // B = (DATA_TYPE (*)[NJ])__builtin_assume_aligned(B, 64);
  ...
  #pragma omp simd
  for (j=...)
    C[i][j] += aik * B[k][j];
}
编译选项建议：-O3 -march=native -ffast-math（若允许）或至少开启 FMA；ICC/ICX/Clang/GCC 均可受益。

推荐并行粒度（tile 级）：
#pragma omp parallel for collapse(2) schedule(static)
for (int ii=0; ii<ni; ii+=BI)
  for (int jj=0; jj<nj; jj+=BJ)
    ... // 内部保持串行 k，更新该 C tile
或简单版本：
#pragma omp parallel for schedule(static)
for (int i=0;i<ni;i++) { ... }
注意：collapse(2) 通常负载更均衡；线程数与 NUMA 需配合 first-touch 初始化或 numactl。

对 (i,j,k) 做 2D/3D 分块：例如 i/j 分块到 BI/BJ，k 分块到 BK；块内采用 ikj 并在寄存器累加一个小的 j 向量（如 8/16 元素）。
伪代码（第一段）：
for(ii=0;ii<NI;ii+=BI)
 for(jj=0;jj<NJ;jj+=BJ)
  for(kk=0;kk<NK;kk+=BK)
   for(i=ii;i<min(ii+BI,NI);i++)
    for(k=kk;k<min(kk+BK,NK);k++){
      aik=alpha*A[i][k];
      for(j=jj;j<min(jj+BJ,NJ);j++) tmp[i][j]+=aik*B[k][j];
    }
第二段同理（把 C 的 k 维分块）。BI/BJ/BK 需按缓存大小与 SIMD 宽度调参（如 BJ=64~256，BK=32~128）。

1) 预处理：生成BT[j][k]=B[k][j]（或按块pack B）以把内层k访问变为连续。
2) 分块：对(i,j,k)做tile，例如 Ti=32,Tj=32,Tk=64（按L1/L2调参）。
3) 向量化：内层对j做向量化（或对k做向量化但需规约），使用#pragma omp simd或编译器自动向量化；对E的累加使用局部寄存器。
4) 并行：#pragma omp parallel for collapse(2) schedule(static) 作用于(i0,j0)块。

示例（简化，假设已分配BT[NJ][NK]）：
// transpose B once
for (int k=0;k<nk;k++)
  for (int j=0;j<nj;j++) BT[j][k]=B[k][j];

#pragma omp parallel for collapse(2) schedule(static)
for (int i0=0;i0<ni;i0+=Ti)
  for (int j0=0;j0<nj;j0+=Tj)
    for (int k0=0;k0<nk;k0+=Tk)
      for (int i=i0;i<min(i0+Ti,ni);i++)
        for (int j=j0;j<min(j0+Tj,nj);j++) {
          DATA_TYPE sum = (k0==0)? SCALAR_VAL(0.0) : E[i][j];
          #pragma omp simd reduction(+:sum)
          for (int k=k0;k<min(k0+Tk,nk);k++)
            sum += A[i][k]*BT[j][k];
          E[i][j]=sum;
        }

编译建议：-O3 -march=native -ffast-math（若允许）并确保restrict/对齐。

示例（以 JB=4 为例，保持下三角）：

for (int i=0;i<_PB_N;i++) {
  for (int jb=0; jb<=i; jb+=JB) {
    int jmax = (jb+JB-1<=i)? (jb+JB-1): i;
    DATA_TYPE cij[JB];
    #pragma unroll
    for (int t=0;t<JB;t++) {
      int j = jb+t;
      if (j<=jmax) cij[t] = beta * C[i][j];
    }
    for (int k=0;k<_PB_M;k++) {
      DATA_TYPE aik = A[i][k];
      #pragma unroll
      for (int t=0;t<JB;t++) {
        int j = jb+t;
        if (j<=jmax) cij[t] += alpha * aik * A[j][k];
      }
    }
    #pragma unroll
    for (int t=0;t<JB;t++) {
      int j = jb+t;
      if (j<=jmax) C[i][j] = cij[t];
    }
  }
}

并配合编译器选项：-O3 -ffast-math（若允许）以及 #pragma omp simd / #pragma clang loop vectorize(enable) 促进向量化。

方案A（不改变数据结构）：k 分块 + j 分块（与上条可叠加）：

const int KB=128; // 依据 L2/L3 调参
for (int i=0;i<_PB_N;i++) {
  for (int jb=0; jb<=i; jb+=JB) {
    init cij[] = beta*C...
    for (int kb=0; kb<_PB_M; kb+=KB) {
      int kend = (kb+KB<_PB_M)? kb+KB : _PB_M;
      for (int k=kb;k<kend;k++) {
        DATA_TYPE aik = A[i][k];
        for (t...) cij[t] += alpha*aik*A[j][k];
      }
    }
    store back
  }
}

方案B（改变数据布局/一次性预处理）：构造 AT[k][j]=A[j][k]（M×N），则内层访问 AT[k][j] 连续：

// 预处理一次：for j in [0..N) for k in [0..M) AT[k][j]=A[j][k]
// kernel: C[i][j]+=alpha*A[i][k]*AT[k][j]

AT 可用 aligned_alloc + restrict 指针，提升向量化与带宽利用。

示例：

#pragma omp parallel for schedule(static)
for (int i=0;i<_PB_N;i++) {
  // 每个线程独占一行 i 的 C[i][0..i]
  for (int jb=0; jb<=i; jb+=JB) { ... }
}

并在内层加：
#pragma omp simd
for (int t=0; t<JB; t++) ...

建议同时使用 restrict：
void kernel_syrk(..., DATA_TYPE (*restrict C)[N], DATA_TYPE (*restrict A)[M])

替换 kernel 为：

// C := alpha*A*A^T + beta*C, lower triangle
cblas_dsyrk(CblasRowMajor, CblasLower, CblasNoTrans,
            n, m, alpha, &A[0][0], m, beta, &C[0][0], n);

并确保链接到优化 BLAS（如 -lmkl_rt 或 -lopenblas）。

1) 确保 A/C 64B 对齐（PolyBench 通常已对齐，但可确认）。
2) 在 kernel 参数上加 restrict。
3) 编译：gcc/clang 使用 -O3 -march=native -funroll-loops；若允许非严格 IEEE：-ffast-math。
4) 可加 __builtin_assume_aligned 指示：
A = (DATA_TYPE (*)[M])__builtin_assume_aligned(A, 64);
C = (DATA_TYPE (*)[N])__builtin_assume_aligned(C, 64);

将 alpha 提前融合到 A/B，或在 (i,k) 层缓存 aik/bik；将内层更新改写为两个乘加，减少重复乘法并利于编译器生成 FMA。
示例：
for (i...) {
  for (j<=i) C[i][j]*=beta;
  for (k...) {
    DATA_TYPE aik = A[i][k];
    DATA_TYPE bik = B[i][k];
    DATA_TYPE a_bik = alpha*bik;
    DATA_TYPE a_aik = alpha*aik;
    for (j<=i) {
      C[i][j] += A[j][k]*a_bik + B[j][k]*a_aik;
    }
  }
}
可选：若允许预处理，先做 A*=alpha 或 B*=alpha（一次性缩放），内核中去掉 alpha 乘法。

当前内层按 j 扫描会以步长 M 访问 A[j][k]、B[j][k]（跨行）。可引入转置缓冲 AT[k][j]=A[j][k], BT[k][j]=B[j][k]（k-major），使内层 j 访问连续：
1) 预处理一次：for (j=0..n-1) for (k=0..m-1) AT[k][j]=A[j][k]; BT[k][j]=B[j][k];
2) 内核：for (k...) { for (j<=i) C[i][j] += AT[k][j]*a_bik + BT[k][j]*a_aik; }
若内存受限，可按 k 分块 pack：每次处理 k0..k0+Kb-1，将 A/B 的该 k-block 打包为连续缓冲再计算。

对 (i,j) 做块化，固定一个 C tile (Ib x Jb)，在 k 上循环累加，尽量让该 tile 常驻 L1/L2：
for (ii=0; ii<n; ii+=Ib)
  for (jj=0; jj<=ii; jj+=Jb) {
    // scale C tile by beta
    for (i=ii..min(ii+Ib)) for (j=jj..min(jj+Jb, i)) C[i][j]*=beta;
    for (k=0; k<m; k+=Kb) {
      // pack A/B panels for this tile if needed
      for (i tile) for (j tile) for (kk=k..k+Kb)
        C[i][j] += A[j][kk]*alpha*B[i][kk] + B[j][kk]*alpha*A[i][kk];
    }
  }
Ib/Jb/Kb 依据缓存大小调参（例如 L1 32KB：Jb*Ib*sizeof(DATA_TYPE) + pack 缓冲需受控）。

按 i 并行最简单（每个线程写不同的 C[i][0..i]）：
#pragma omp parallel for schedule(static)
for (i=0; i<n; i++) {
  ...
}
若采用 tiling，可对 (ii,jj) tile 并行；确保每个 tile 覆盖的 C 区域互不重叠（下三角）。

示例（保持语义不变）：

// 假设 DATA_TYPE 为 double/float
const int PB = 64;   // p-block (按L1/L2调参)
const int SB = 64;   // s-block
for (int r=0; r<_PB_NR; ++r)
  for (int q=0; q<_PB_NQ; ++q) {
    // 分块初始化 sum
    for (int p0=0; p0<_PB_NP; p0+=PB) {
      int pmax = (p0+PB<_PB_NP)?(p0+PB):_PB_NP;
      for (int p=p0; p<pmax; ++p) sum[p] = 0;
      // s 分块累加
      for (int s0=0; s0<_PB_NP; s0+=SB) {
        int smax = (s0+SB<_PB_NP)?(s0+SB):_PB_NP;
        for (int s=s0; s<smax; ++s) {
          DATA_TYPE a = A[r][q][s];
          // 内层 p 连续访问 C4[s][p]
          #pragma omp simd
          for (int p=p0; p<pmax; ++p)
            sum[p] += a * C4[s][p];
        }
      }
      // 写回 A
      #pragma omp simd
      for (int p=p0; p<pmax; ++p)
        A[r][q][p] = sum[p];
    }
  }

要点：把原来的 (p){(s){...}} 结构改为 (p块){(s块){s外提，p内向量化}}，使 C4[s][p] 在 p 维连续、易向量化，并让 C4 子块在缓存中复用。

关键点：sum 目前是共享数组，会产生数据竞争；需每线程私有。

方案A（推荐）：在并行域内为每线程分配局部 sum_buf：
#pragma omp parallel
{
  std::vector<DATA_TYPE> sum_buf(_PB_NP);
  #pragma omp for collapse(2) schedule(static)
  for (int r=0; r<_PB_NR; ++r)
    for (int q=0; q<_PB_NQ; ++q) {
      // 用 sum_buf 替代 sum
      ... sum_buf[p] ...
      ... A[r][q][p] = sum_buf[p] ...
    }
}

方案B：若必须用 C 数组，可用 alloca 或 omp_alloc 分配线程私有缓冲。

注意：并行粒度为 NR*NQ 个独立任务，通常足够大。

思路：把 A 视为矩阵 A2D，维度 M=(NR*NQ), K=NP；C4 为 K×N (N=NP)。
目标：A2D = A2D * C4 （右乘）。

实现：
1) 重新解释/重排 A 为连续的 (M×K) 行主序（PolyBench A 本身最后一维连续，(r,q) 展平后也连续）。
2) 调用 GEMM：C = A2D * C4，其中 C 覆盖写回 A2D。
需要临时输出缓冲 B(M×N) 或就地算法（多数BLAS不支持就地）。

伪码：
DATA_TYPE* A2 = &A[0][0][0];
// allocate tmp M*NP
cblas_dgemm(RowMajor, NoTrans, NoTrans, M, NP, NP, 1.0, A2, NP, &C4[0][0], NP, 0.0, tmp, NP);
memcpy(A2, tmp, M*NP*sizeof(DATA_TYPE));

若保持原循环 (p 外, s 内)，则访问 C4[s][p] 对 s 连续、对内存是跨行跳跃（Row-major 下步长 NP），不利缓存。
两种做法：
1) 预转置：C4T[p][s]=C4[s][p]，然后用 C4T[p][s] 使 s 内层连续。
2) 更推荐配合分块：对每个 s0..s0+SB, p0..p0+PB 打包到连续缓冲 packC[SB][PB]，内核只访问 packC。

预转置代码：
for (int s=0;s<NP;++s)
  for (int p=0;p<NP;++p)
    C4T[p][s]=C4[s][p];

1) 计算 inv = 1.0 / R[k][k]；
   DATA_TYPE inv = SCALAR_VAL(1.0)/R[k][k];
   #pragma omp simd
   for(i=0;i<m;i++) Q[i][k] = A[i][k]*inv;
2) 可选融合(两遍变一遍)：先算 nrm 后仍需再扫一遍写 Q；若接受更激进改动，可在块内缓存 A[:,k] 到临时缓冲(见后续 blocking)以减少从内存重复取数。

方案A(保持结构，减少内存流量)：对每个 j 仍需先得到 R[k][j] 才能更新 A[:,j]，但可以对 j 做分块并缓存 Q[:,k]：
- 预先将 Q[:,k] 拷贝到连续临时数组 qk[i]（长度 m），提高后续访问局部性：
  static DATA_TYPE qk[M];
  #pragma omp simd
  for(i=0;i<m;i++) qk[i]=Q[i][k];
- 对 j 做块：for(jb=k+1; jb<n; jb+=JB){ je=min(n,jb+JB);
    // 1) 计算一块的 R[k][j]
    for(j=jb;j<je;j++){ sum=0; #pragma omp simd reduction(+:sum) for(i=0;i<m;i++) sum += qk[i]*A[i][j]; R[k][j]=sum; }
    // 2) 用已得 R 更新 A（同一块，尽量让 A 块驻留缓存）
    for(j=jb;j<je;j++){ r=R[k][j]; #pragma omp simd for(i=0;i<m;i++) A[i][j] -= qk[i]*r; }
  }
  其中 JB 取使 A 的 (m x JB) 子块适配 LLC/L2（经验：JB=8..64）。

方案B(更推荐，利用 BLAS 将热点变为高效内核)：
- 计算 r = Q[:,k]^T * A[:,k+1:n-1] 这是一个 GEMV：
  cblas_dgemv(CblasRowMajor, CblasTrans, m, n-k-1, 1.0, &A[0][k+1], N, &Q[0][k], N, 0.0, &R[k][k+1], 1);
- 更新 A[:,k+1:] -= Q[:,k] * r 这是一个 GER(rank-1 update)：
  cblas_dger(CblasRowMajor, m, n-k-1, -1.0, &Q[0][k], N, &R[k][k+1], 1, &A[0][k+1], N);
  这样把大量标量循环交给高度优化的向量化/预取实现，并改善缓存复用。

并行化注意：k 迭代存在依赖，不能跨 k 并行；但在固定 k 内可并行 j(列) 或 i(行) reduction。若用 OpenMP：
- 对每个 j 的点积可用 omp parallel for + 私有 sum + reduction(手工)；或对 i 做并行 reduction（更复杂）。
- 更简单：并行 j：
  #pragma omp parallel for schedule(static)
  for(j=k+1;j<n;j++){ ... dot ...; ... update ... }
  但 update 需要先得到 R[k][j]，同一 j 内顺序即可。

将原始 i-j-k 改为 i-k-j：

for (int i=0;i<M;i++) {
  for (int j=0;j<N;j++) B[i][j] *= alpha; // 先缩放，避免最后一次写回前后依赖
  for (int k=i+1;k<M;k++) {
    DATA_TYPE aik = A[k][i];
    #pragma omp simd
    for (int j=0;j<N;j++) {
      B[i][j] += aik * B[k][j];
    }
  }
}

说明：1) B[k][j] 在 j 上连续，利于 SIMD/预取；2) A[k][i] 标量复用；3) 先做 alpha 缩放可减少一次对 B[i][j] 的读-改-写链并利于向量化（也可融合到最后，但先缩放更易并行/向量化）。

对 j 做块化（JB 例如 64/128，按元素大小与 SIMD 宽度调参）：

const int JB = 128;
for (int i=0;i<M;i++) {
  for (int jj=0;jj<N;jj+=JB) {
    int jend = (jj+JB<N)?(jj+JB):N;
    for (int j=jj;j<jend;j++) B[i][j] *= alpha;
    for (int k=i+1;k<M;k++) {
      DATA_TYPE aik = A[k][i];
      #pragma omp simd
      for (int j=jj;j<jend;j++) B[i][j] += aik * B[k][j];
    }
  }
}

可选：对 k 也分块（KB）以让 B[k][jj:jend] 的访问更集中，减少跨 i 的缓存抖动。

由于 B[i][j] 读取 B[k>i][j]，若按 i 从大到小计算，则 B[k][j] 已经是最终值且不会再被写，从而 i 之间无写后读冲突：

#pragma omp parallel for schedule(static)
for (int ii=M-1; ii>=0; --ii) {
  int i = ii;
  for (int j=0;j<N;j++) B[i][j] *= alpha;
  for (int k=i+1;k<M;k++) {
    DATA_TYPE aik = A[k][i];
    #pragma omp simd
    for (int j=0;j<N;j++) B[i][j] += aik * B[k][j];
  }
}

注意：需要确认数学等价性（本 kernel 对 B 的更新只写 B[i][*]，读取 B[k][*]；逆序可保证读取到的是最终 B[k][*]）。

在每个 tstep 的 Column Sweep 前，将 u 的列方向数据打包为连续数组（或维护 uT=transpose(u) 使列访问变为行访问）。示例（packing）：
1) 分配临时缓冲：DATA_TYPE *uc = aligned_alloc(64, n*sizeof(DATA_TYPE));
2) 对固定 i：for (j=0;j<n;j++) uc[j]=u[j][i]; 同时需要 u[j][i-1],u[j][i+1] 可打包为 ucm1/ucp1 或在打包时读取。
3) Thomas 前向：使用 uc/ucm1/ucp1 计算 q/p；回代写回 vc[j]；最后 for (j=0;j<n;j++) v[j][i]=vc[j];
若允许更大改动：维护 uT[i][j]=u[j][i]、vT 同理，Column Sweep 直接在 uT 的行上做连续访问，结束后再转置回或后续都用转置布局。

将分母 denom = a*p[i][j-1]+b 提取并用倒数替代除法：
for (j=1; j<n-1; j++) {
  DATA_TYPE denom = a*pijm1 + b; // pijm1 = p[i][j-1]
  DATA_TYPE inv = SCALAR_VAL(1.0)/denom;
  p[i][j] = -c * inv;
  q[i][j] = (rhs - a*qijm1) * inv;
}
同时用局部标量缓存 p[i][j-1], q[i][j-1]（避免重复从内存读）：
DATA_TYPE pijm1=p[i][0], qijm1=q[i][0];
循环内更新 pijm1=qijm1。
为编译器提供别名信息：将 kernel_adi 形参改为 DATA_TYPE (*restrict u)[N] 等，或在 PolyBench 宏外包一层 restrict 指针；并确保 64B 对齐（PolyBench 通常已对齐，但可显式使用 aligned_alloc/posix_memalign）。

将边界赋值与主循环拆分，减少分支/写入干扰：
for (i=1;i<n-1;i++) { u[i][0]=1; p[i][0]=0; q[i][0]=1; }
for (i=1;i<n-1;i++) {
  DATA_TYPE pijm1=0, qijm1=1;
  for (j=1;j<n-1;j++) {
    DATA_TYPE denom = d*pijm1 + e;
    DATA_TYPE inv = 1/denom;
    DATA_TYPE rhs = (-a*v[i-1][j] + (1+2*a)*v[i][j] - c*v[i+1][j]);
    DATA_TYPE pij = -f*inv;
    DATA_TYPE qij = (rhs - d*qijm1)*inv;
    p[i][j]=pij; q[i][j]=qij;
    pijm1=pij; qijm1=qij;
  }
}
回代同理用局部缓存减少读：
DATA_TYPE unext = u[i][n-1]=1; for (j=n-2;j>=1;j--) { unext = p[i][j]*unext + q[i][j]; u[i][j]=unext; }
并可加编译器提示：#pragma clang loop unroll(enable) 或 #pragma GCC unroll 4（谨慎，避免 I-cache 压力）。

观察到 p[i][j], q[i][j] 仅在同一 i 的前向/回代中使用，可将 p/q 从 2D 改为 1D 临时数组（长度 n），每个 i 重用：
DATA_TYPE *p1 = aligned_alloc(64,n*sizeof(DATA_TYPE));
DATA_TYPE *q1 = aligned_alloc(64,n*sizeof(DATA_TYPE));
for (i=1;i<n-1;i++) { p1[0]=0; q1[0]=...; for (j=1;j<n-1;j++){... p1[j]=...; q1[j]=...;} for (j=n-2;j>=1;j--){ v[j][i]=p1[j]*v[j+1][i]+q1[j]; } }
Row Sweep 同理。
这样将 p/q 的写流量从 O(n^2) 降到 O(n)（每 i），显著降低内存带宽压力与缓存污染。

